#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int* A = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        int* stacks = (int*)malloc(N * sizeof(int));
        int top = 0;
        for (int i = 0; i < N; i++) {
            int found = 0;
            for (int j = 0; j < top; j++) {
                if (A[i] < stacks[j]) {
                    stacks[j] = A[i];
                    found = 1;
                    break;
                }
            }
            if (!found) {
                stacks[top] = A[i];
                top++;
            }
        }
        printf("%d", top);
        for (int i = 0; i < top; i++) {
            printf(" %d", stacks[i]);
        }
        printf("\n");
        free(A);
        free(stacks);
    }
    return 0;
}

