        int N;
        cin >> N;
        vector<int> A(N);
        for (int i = 0; i < N; i++) {
            cin >> A[i];
        }
        vector<int> stacks;
        for (int i = 0; i < N; i++) {
            int found = 0;
            for (int j = 0; j < stacks.size(); j++) {
                if (A[i] < stacks[j]) {
                    stacks[j] = A[i];
                    found = 1;
                    break;
                }
            }
            if (!found) {
                stacks.push_back(A[i]);
            }
        }
        cout << stacks.size();
        for (int i = 0; i < stacks.size(); i++) {
            cout << " " << stacks[i];
        }
        cout << endl;
    }
    return 0;
}

