const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];

const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const N = parseInt(readline());
    const A = readline().split(' ').map(x => parseInt(x));
    const stacks = [];
    for (let j = 0; j < N; j++) {
        let found = false;
        for (let k = 0; k < stacks.length; k++) {
            if (A[j] < stacks[k]) {
                stacks[k] = A[j];
                found = true;
                break;
            }
        }
        if (!found) {
            stacks.push(A[j]);
        }
    }
    process.stdout.write(stacks.length.toString());
    for (let j = 0; j < stacks.length; j++) {
        process.stdout.write(' ' + stacks[j].toString());
    }
    process.stdout.write('\n');
}
